function g(id){return document.getElementById(id);}
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function col(s){return s==null?"#9ca3af":s>=90?"#22c55e":s>=50?"#f59e0b":"#ef4444";}
function rating(s){return s==null?"":s>=90?"Good":s>=50?"Needs Work":"Poor";}

// ── EXTRA SITES (localStorage) ────────────────────────
function loadExtraSites(){
  try{
    var raw=localStorage.getItem(EXTRA_KEY);
    if(raw){
      var extra=JSON.parse(raw);
      extra.forEach(function(s){
        if(!SITES.some(function(x){return x.url===s.url;})){SITES.push(s);}
      });
    }
  }catch(e){}
  updateSiteCount();
}

function saveExtraSites(){
  try{
    var defaults=SITES_DEFAULT.map(function(s){return s.url;});
    var extra=SITES.filter(function(s){return defaults.indexOf(s.url)===-1;});
    localStorage.setItem(EXTRA_KEY,JSON.stringify(extra));
  }catch(e){}
}

function updateSiteCount(){
  var el=g("site-count");
  if(el){el.textContent=SITES.length+" Duda websites";}
}

